parameters.jsCode:
return items.map(item => {
  let raw = item.json.text || item.json.output || item.json.data || "";

  // Step 1: Clean string (remove unwanted characters if needed)
  raw = raw.trim();

  // Step 2: Parse JSON safely
  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch (err) {
    // fallback: try to fix broken JSON
    parsed = JSON.parse(
      raw
        .replace(/\n/g, "")
        .replace(/\r/g, "")
        .replace(/\t/g, "")
    );
  }

  // Step 3: Normalize probability (0–1 → %)
  if (parsed.probability_1 <= 1) {
    parsed.probability_1 = Math.round(parsed.probability_1 * 100);
  }

  if (parsed.confidence_1 <= 1) {
    parsed.confidence_1 = Math.round(parsed.confidence_1 * 100);
  }

  // Step 4: Ensure missing fields don’t break template
  parsed.symptoms = parsed.symptoms || "";
  parsed.remedy_1 = parsed.remedy_1 || "";
  parsed.follow_up_needed = parsed.follow_up_needed || "MONITOR";

  return {
    json: parsed
  };
});

