// Current form data
const current = $('Extract Form Data').first().json;

// Existing student data
const existing = $('Searches for student').first().json;

// --- SAFETY ---
if (!existing || !existing.row_number) {
  throw new Error("No valid existing user found");
}

// --- CURRENT VALUES ---
const currSleep = Number(current.sleep_hours) || 0;
const currStress = Number(current.stress_level) || 0;
const currEnergy = Number(current.energy_level) || 0;

const currSymptomsArr = current.symptoms || [];
const currSymptomsStr = current.symptoms_string || "";
const currSymptomCount = currSymptomsArr.length;

// --- PREVIOUS VALUES ---
const prevSleep = Number(existing.latest_sleep) || 0;
const prevStress = Number(existing.latest_stress) || 0;
const prevEnergy = Number(existing.latest_energy) || 0;

const prevSymptomsStr = existing.latest_symptoms || "";
const prevSymptomsArr = prevSymptomsStr ? prevSymptomsStr.split(',').map(s => s.trim()) : [];
const prevSymptomCount = prevSymptomsArr.length;

// --- TREND CALCULATION ---
const sleep_trend =
  currSleep > prevSleep ? "Improving" :
  currSleep < prevSleep ? "Declining" : "Stable";

const stress_trend =
  currStress < prevStress ? "Improving" :
  currStress > prevStress ? "Declining" : "Stable";

const energy_trend =
  currEnergy > prevEnergy ? "Improving" :
  currEnergy < prevEnergy ? "Declining" : "Stable";

// --- SYMPTOM TREND ---
const symptom_trend =
  currSymptomCount < prevSymptomCount ? "Improving" :
  currSymptomCount > prevSymptomCount ? "Worsening" : "Stable";

// --- POINT SYSTEM ---
let points = 10;

// Improvements
if (currSleep > prevSleep) points += 15;
if (currStress < prevStress) points += 15;
if (currEnergy > prevEnergy) points += 15;
if (currSymptomCount < prevSymptomCount) points += 20; // NEW (important)

// Healthy habits
if (currSleep >= 7) points += 10;
if (currStress <= 3) points += 10;
if (currEnergy >= 4) points += 10;

// Penalty for worsening symptoms
if (currSymptomCount > prevSymptomCount) points -= 5;

// --- STREAK ---
const lastDate = new Date(existing.last_submission);
const currentDate = new Date(current.submission_date);

const diffDays = (currentDate - lastDate) / (1000 * 60 * 60 * 24);

let streak = existing.streak || 1;

if (diffDays <= 1) {
  streak += 1;
} else {
  streak = 1;
}

// Streak bonus
if (streak >= 4) points += 25;
else if (streak >= 2) points += 10;

// --- TOTAL POINTS ---
const total_points = (existing.total_points || 0) + points;

// --- OUTPUT ---
return [{
  json: {
    ...current,

    row_number: existing.row_number,

    // updated stats
    submission_count: (existing.submission_count || 0) + 1,
    total_points,
    points_earned_this_log: points,
    streak,

    // latest values
    latest_sleep: currSleep,
    latest_stress: currStress,
    latest_energy: currEnergy,
    latest_symptoms: currSymptomsStr,  // NEW

    // previous values
    previous_sleep: prevSleep,
    previous_stress: prevStress,
    previous_energy: prevEnergy,
    previous_symptom_count: prevSymptomCount,

    // trends
    sleep_trend,
    stress_trend,
    energy_trend,
    symptom_trend,

    // counts
    current_symptom_count: currSymptomCount,

    is_returning: true,
    last_submission: current.submission_date
  }
}];

return items.map(item => {
  // Step 1: parse the string
