    data.probability_1 = Math.round(data.probability_1 * 100);
  }

  if (data.confidence_1 <= 1) {
    data.confidence_1 = Math.round(data.confidence_1 * 100);
  }

  // Step 3: return clean JSON
  return {
    json: data
  };
